import React from "react";
import axios from "axios";

const DatabaseSelector = ({ setDb }) => {
  const handleSelect = async (dbType) => {
    try {
      await axios.post("http://localhost:5000/api/items/set-db", { dbType });
      setDb(dbType);
    } catch (err) {
      console.error("Database selection failed", err);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen gap-10">
      <h1 className="text-5xl font-extrabold text-gray-800">Select Database</h1>
      <div className="flex gap-8">
        {["mysql", "sqlite", "mongodb"].map((dbType) => (
          <button
            key={dbType}
            onClick={() => handleSelect(dbType)}
            className="px-8 py-6 bg-gradient-to-r from-blue-500 to-purple-500 text-white text-2xl font-semibold rounded-xl shadow-lg hover:scale-105 transition transform"
          >
            {dbType.toUpperCase()}
          </button>
        ))}
      </div>
    </div>
  );
};

export default DatabaseSelector;
